# --- TLS Configuration ---

def load_tls_credentials() -> Optional[grpc.ServerCredentials]:
    """
    Load TLS credentials from files specified by environment variables.
    Returns None if TLS is not configured.
    """
    cert_path = os.environ.get('GRPC_TLS_CERT_PATH')
    key_path = os.environ.get('GRPC_TLS_KEY_PATH')
    ca_cert_path = os.environ.get('GRPC_TLS_CA_CERT_PATH')
    
    if not cert_path or not key_path:
        return None
    
    try:
        with open(cert_path, 'rb') as f:
            server_cert = f.read()
        with open(key_path, 'rb') as f:
            server_key = f.read()
        
        ca_cert = None
        require_client_auth = False
        if ca_cert_path:
            with open(ca_cert_path, 'rb') as f:
                ca_cert = f.read()
            require_client_auth = True
        
        credentials = grpc.ssl_server_credentials(
            [(server_key, server_cert)],
            root_certificates=ca_cert,
            require_client_auth=require_client_auth,
        )
        
        logger.info(
            "TLS configured (mutual TLS: %s)",
            "enabled" if require_client_auth else "disabled"
        )
        return credentials
        
    except FileNotFoundError as e:
        logger.error("TLS certificate file not found: %s", e)
        raise
    except Exception as e:
        logger.error("Failed to load TLS credentials: %s", e)
        raise


